package com.khanh.fooddelivery.restaurant_service.entity;
import com.khanh.fooddelivery.restaurant_service.common.entity.BaseAuditEntity; import com.khanh.fooddelivery.restaurant_service.enums.*; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="restaurant_partner_applications") @Getter @Setter @NoArgsConstructor
public class RestaurantPartnerApplication extends BaseAuditEntity {@Id private UUID id; @Column(nullable=false) private UUID applicantUserId; @Column(nullable=false) private String businessName; @Enumerated(EnumType.STRING) private BusinessType businessType; private String taxCode; @Column(nullable=false) private String representativeName; @Column(nullable=false) private String representativePhone; private String representativeEmail; @Column(columnDefinition="text") private String description; @Column(nullable=false) private String city; private String district; @Column(nullable=false) private String businessAddress; @Column(nullable=false) private Integer expectedBranchCount=1; private Integer estimatedDailyOrders; private String mainCuisine; @Enumerated(EnumType.STRING) @Column(nullable=false) private PartnerApplicationStatus status; private Instant submittedAt; private Instant reviewedAt; private UUID reviewedByUserId; private String rejectionReason; @Version private long version; @OneToMany(mappedBy="application",fetch=FetchType.LAZY,cascade=CascadeType.ALL,orphanRemoval=true) private List<RestaurantApplicationDocument> documents=new ArrayList<>(); @PrePersist void id(){if(id==null)id=UUID.randomUUID();}}
